package com.chaobo.scm.supplier.infrastructure.persistence.item;import org.apache.ibatis.annotations.*;import java.math.*;import java.time.*;
@Mapper public interface SupplierItemPriceSnapshotMapper{@Insert("INSERT INTO sup_supplier_item_price_snapshot(snapshot_id,supplier_id,sku_code,agreement_ref,currency,unit_price,tax_rate,effective_from,effective_to,source_contract_id,source_quote_id,source_version) VALUES(#{id},#{supplierId},#{skuCode},#{agreementRef},#{currency},#{unitPrice},#{taxRate},#{effectiveFrom},#{effectiveTo},#{contractId},#{quoteId},#{version}) ON DUPLICATE KEY UPDATE unit_price=VALUES(unit_price),tax_rate=VALUES(tax_rate),effective_from=VALUES(effective_from),effective_to=VALUES(effective_to)")void upsert(@Param("id")long id,@Param("supplierId")long supplierId,@Param("skuCode")String skuCode,@Param("agreementRef")String agreementRef,@Param("currency")String currency,@Param("unitPrice")BigDecimal unitPrice,@Param("taxRate")BigDecimal taxRate,@Param("effectiveFrom")LocalDate effectiveFrom,@Param("effectiveTo")LocalDate effectiveTo,@Param("contractId")long contractId,@Param("quoteId")long quoteId,@Param("version")int version);}
